      "Moved models.providers.openai-codex.api \"openai-codex-responses\" → \"openai-chatgpt-responses\".",
      "Merged 1 model(s) from models.providers.openai-codex into models.providers.openai: gpt-5.5."
    ]
  },
  "matchingPlusDisjoint": {
    "providers": {
